parameters.jsCode:
const prefs = $('Get Preferences').first().json.data;
const business = $('Get Business').first().json.data;
const wh = $('Webhook').first().json.body;
const brief = wh.brief || {};
const platform = (wh.platform || 'instagram').toLowerCase();

const rules = {
  instagram: 'Platform: Instagram. Warm and visual. 1-3 emojis. 80-150 words. 5-10 hashtags.',
  linkedin: 'Platform: LinkedIn. Professional, credible. Avoid emojis. 100-160 words. 3-5 professional hashtags.',
  facebook: 'Platform: Facebook. Conversational. Up to 180 words. 0-2 hashtags.',
  twitter: 'Platform: X (Twitter). Caption + hashtags must be under 280 chars total. 1-2 hashtags.'
};

return [{ json: {
  slot_id: wh.slot_id,
  business_id: wh.business_id,
  platform: platform,
  num_variants: wh.num_variants || 3,
  business_name: business.name,
  industry: business.industry,
  brand_tone: prefs.brand_tone,
  brief_hook: brief.hook || '',
  brief_key_message: brief.key_message || '',
  brief_emotional_angle: brief.emotional_angle || '',
  brief_cta: brief.cta || '',
  platform_rules: rules[platform] || 'Standard platform rules.'
}}];

