parameters.jsCode:
const ctx = $('Merge Context').first().json;
let raw;
try { raw = $input.first().json.output[0].content[0].text; }
catch(e) { throw new Error('No AI response text — unexpected OpenAI output structure.'); }
const cleaned = (raw || '').replace(/```json/gi, '').replace(/```/g, '').trim();

let variants;
try { variants = JSON.parse(cleaned); }
catch(e) { throw new Error('AI did not return valid JSON. Raw start: ' + cleaned.slice(0,200)); }
if (!Array.isArray(variants) || variants.length === 0) {
  throw new Error('Expected non-empty array of variants');
}

return variants.map((v, i) => {
  const hashtags = Array.isArray(v.hashtags) ? v.hashtags : [];
  const fullText = (v.caption || '') + (hashtags.length ? ' ' + hashtags.join(' ') : '');
  // X hard limit warning (don't throw, just flag — A/B reviewer can ignore the variant)
  const exceeds_x_limit = (ctx.platform === 'twitter' && fullText.length > 280);

  return { json: {
    variant_id: 'var_' + ctx.slot_id + '_v' + (i+1) + '_' + Date.now(),
    variant_index: i + 1,
    slot_id: ctx.slot_id,
    business_id: ctx.business_id,
    platform: ctx.platform,
    label: v.label || ('variant_' + (i+1)),
    approach: v.approach || '',
    hook: v.hook || '',
    caption: v.caption || '',
    hashtags: hashtags,
    cta: v.cta || '',
    char_count: fullText.length,
    exceeds_x_limit: exceeds_x_limit
  }};
});

const variants = $input.all().map(i => i.json);
const wh = $('Webhook').first().json.body;
return [{ json: {
  success: true,
  slot_id: wh.slot_id,
  platform: wh.platform,
  variant_count: variants.length,
  variants: variants.map(v => ({
    variant_id: v.variant_id,
    label: v.label,
    approach: v.approach,
    hook: v.hook,
    caption: v.caption,
    hashtags: v.hashtags,
    cta: v.cta,
    char_count: v.char_count,
    exceeds_x_limit: v.exceeds_x_limit
  }))
}}];
